  role: 'admin' | 'user';
}

type UserPatch = Partial<User>;
// { id?: number; name?: string; email?: string; role?: 'admin' | 'user' }

// Update function — caller provides only the fields that change
function updateUser(id: number, patch: Partial<User>): void {
  // patch may have some or none of the User fields
}

updateUser(1, { name: 'Alice' });         // ok — only name
updateUser(1, { role: 'admin' });         // ok — only role
updateUser(1, { name: 'Bob', email: 'b@example.com' }); // ok — two fields

// Partial<T> does NOT make nested objects partial — only top-level properties
interface Config {
  server: { host: string; port: number };
  debug: boolean;
}

type PartialConfig = Partial<Config>;
// { server?: { host: string; port: number }; debug?: boolean }
// server itself is optional, but host and port inside are still required

interface Config {
  host?: string;
  port?: number;
  timeout?: number;
  debug?: boolean;
}

type FullConfig = Required<Config>;
// { host: string; port: number; timeout: number; debug: boolean }

const DEFAULTS: Required<Config> = {
  host:    'localhost',
  port:    3000,
  timeout: 5000,
  debug:   false,
};

function resolveConfig(userConfig: Config): Required<Config> {
  return { ...DEFAULTS, ...userConfig };
}

const cfg = resolveConfig({ port: 8080 });
// cfg is Required<Config> — all fields guaranteed present
cfg.host.toUpperCase();    // ok — host is string, not string | undefined
cfg.port.toFixed(0);       // ok — port is number

// Useful pattern: use Partial for input, Required internally
class AppConfig {
  private resolved: Required<Config>;

  constructor(input: Config = {}) {
    this.resolved = resolveConfig(input);
  }

  get host(): string { return this.resolved.host; }
}

interface Point { x: number; y: number; }

type ReadonlyPoint = Readonly<Point>;
// { readonly x: number; readonly y: number; }

const p: ReadonlyPoint = { x: 10, y: 20 };
p.x = 5; // Error: Cannot assign to 'x' because it is a read-only property.
// p.y++;  // Error: same

// Common: immutable function arguments
function render(point: Readonly<Point>): string {
  // TypeScript prevents accidental mutation inside this function
  return `(${point.x}, ${point.y})`;
}

// Readonly only protects the top level — nested objects can still be mutated
interface Tree {
  value: number;
  children: { value: number }[];
}

const tree: Readonly<Tree> = { value: 1, children: [{ value: 2 }] };
// tree.value = 5;         // Error — readonly
// tree.children = [];     // Error — readonly
tree.children[0].value = 9; // OK — children array is Readonly but its elements are not

import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

interface Product {
  id: string;
  name: string;
  price: number;
  stock: number;
  category: string;
  description: string;
}

// PATCH endpoint only needs the fields being updated
type ProductPatch = Partial<Omit<Product, 'id'>>; // id excluded — read-only server field

@Injectable({ providedIn: 'root' })
class ProductService {
  constructor(private http: HttpClient) {}

  update(id: string, patch: ProductPatch): Observable<Product> {
    return this.http.patch<Product>(`/api/products/${id}`, patch);
  }
}

// Caller can update just the price:
productService.update('p1', { price: 19.99 });
// Or just the stock:
productService.update('p1', { stock: 50 });

import { FormBuilder, FormGroup } from '@angular/forms';

interface RegisterForm {
  name?: string;
  email?: string;
  password?: string;
  confirmPassword?: string;
}

// Default values must have all fields for FormBuilder — use Required
const FORM_DEFAULTS: Required<RegisterForm> = {
  name:            '',
  email:           '',
  password:        '',
  confirmPassword: '',
};

@Component({ selector: 'app-register', standalone: true, ... })
export class RegisterComponent {
  form: FormGroup;

  constructor(fb: FormBuilder) {
    // FORM_DEFAULTS satisfies Required<RegisterForm> — all fields present
    this.form = fb.group({
      name:            [FORM_DEFAULTS.name],
      email:           [FORM_DEFAULTS.email],
      password:        [FORM_DEFAULTS.password],
      confirmPassword: [FORM_DEFAULTS.confirmPassword],
    });
  }
}

import { signal, computed } from '@angular/core';

interface AppState {
  user: { id: string; name: string; role: string } | null;
  notifications: { id: string; message: string }[];
  loading: boolean;
}

class StateService {
  // Internal mutable signal
  private _state = signal<AppState>({
    user: null,
    notifications: [],
    loading: false,
  });

  // Public read-only view — consumer cannot call update methods
  readonly state: Signal<Readonly<AppState>> = computed(
    () => this._state() as Readonly<AppState>
  );

  // Only this service can update state
  setLoading(loading: boolean): void {
    this._state.update(s => ({ ...s, loading }));
  }

  setUser(user: AppState['user']): void {
    this._state.update(s => ({ ...s, user }));
  }
}

// Mark @Input arrays as Readonly to prevent child mutations from affecting parent
@Component({ selector: 'app-user-list', standalone: true, template: '...' })
export class UserListComponent {
  @Input({ required: true }) users!: ReadonlyArray<User>;
  // Child cannot call this.users.push(...)  — prevents accidental parent mutation

  @Input() config: Readonly<{ pageSize: number; sortBy: string }> = {
    pageSize: 10,
    sortBy: 'name',
  };
}

interface Document {
  id: string;
  title: string;
  content?: string;
  metadata?: { author: string; tags: string[] };
  createdAt: Date;
  updatedAt: Date;
}

// Draft: partial fields, nothing readonly
type DocumentDraft = Partial<Omit<Document, 'id' | 'createdAt' | 'updatedAt'>>;

// Published: all fields required, fully readable
type PublishedDocument = Required<Document>;

// Frozen snapshot: cannot be mutated, but all optional fields present
type DocumentSnapshot = Readonly<Required<Document>>;

// Merge defaults to go from draft to published
function publishDocument(
  draft: DocumentDraft,
  id: string
): PublishedDocument {
  return {
    id,
    title:    draft.title    ?? 'Untitled',
    content:  draft.content  ?? '',
    metadata: draft.metadata ?? { author: 'Unknown', tags: [] },
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

// DeepPartial — recursively make all properties optional
type DeepPartial<T> = T extends object
  ? { [K in keyof T]?: DeepPartial<T[K]> }
  : T;

// DeepRequired — recursively require all properties
type DeepRequired<T> = T extends object
  ? { [K in keyof T]-?: DeepRequired<T[K]> }
  : T;

// DeepReadonly — recursively freeze all properties
type DeepReadonly<T> = T extends object
  ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;

// Example with nested config
interface AppConfig {
  server: { host: string; port?: number };
  db: { url?: string; pool?: { size?: number } };
}

type DeepConfig = DeepPartial<AppConfig>;
// {
//   server?: { host?: string; port?: number };
//   db?: { url?: string; pool?: { size?: number } };
// }

type FrozenConfig = DeepReadonly<Required<AppConfig>>;
// All properties required AND readonly at every nesting level
